import{_ as r,o as a,c as o,ag as l}from"./chunks/framework.CrllrrHC.js";const _=JSON.parse('{"title":"🔐 Cloudflare Worker：Serverless 边缘鉴权的实现","description":"","frontmatter":{"title":"🔐 Cloudflare Worker：Serverless 边缘鉴权的实现","slug":"cloudflare-worker-auth","date":"2026-05-03T00:00:00.000Z"},"headers":[],"relativePath":"column/blog/003_cloundFlareWorkerAuth.md","filePath":"column/blog/003_cloundFlareWorkerAuth.md"}'),t={name:"column/blog/003_cloundFlareWorkerAuth.md"};function u(i,e,c,d,h,n){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="cloudflare-worker-oauth-鉴权的-中间人" tabindex="-1">Cloudflare Worker：OAuth 鉴权的“中间人” <a class="header-anchor" href="#cloudflare-worker-oauth-鉴权的-中间人" aria-label="Permalink to &quot;Cloudflare Worker：OAuth 鉴权的“中间人”&quot;">​</a></h1><p>🔗链接:<a href="https://www.cloudflare.com/zh-cn/" target="_blank" rel="noreferrer">https://www.cloudflare.com/zh-cn/</a></p><p>在无服务器架构中，Cloudflare Worker 充当了安全的后端代理，处理 GitHub OAuth 流程中的敏感信息。</p><h2 id="_1-为什么选择-cloudflare-worker" tabindex="-1">1. 为什么选择 Cloudflare Worker？ <a class="header-anchor" href="#_1-为什么选择-cloudflare-worker" aria-label="Permalink to &quot;1. 为什么选择 Cloudflare Worker？&quot;">​</a></h2><ul><li><strong>安全性</strong>：在服务端交换 Token，避免 <code>client_secret</code> 在浏览器端暴露。</li><li><strong>低延迟</strong>：运行在 V8 隔离环境中，冷启动几乎为零。</li><li><strong>免费额度</strong>：每天 10 万次请求，足以支撑个人博客的登录需求。</li></ul><h2 id="_2-部署流程" tabindex="-1">2. 部署流程 <a class="header-anchor" href="#_2-部署流程" aria-label="Permalink to &quot;2. 部署流程&quot;">​</a></h2><h3 id="_2-1-创建-github-oauth-app" tabindex="-1">2.1 创建 GitHub OAuth App <a class="header-anchor" href="#_2-1-创建-github-oauth-app" aria-label="Permalink to &quot;2.1 创建 GitHub OAuth App&quot;">​</a></h3><ol><li>在 GitHub 设置中创建 OAuth App。</li><li><strong>Authorization callback URL</strong>: <code>https://你的项目.workers.dev/callback</code>。</li></ol><h3 id="_2-2-核心代码逻辑" tabindex="-1">2.2 核心代码逻辑 <a class="header-anchor" href="#_2-2-核心代码逻辑" aria-label="Permalink to &quot;2.2 核心代码逻辑&quot;">​</a></h3><p>Worker 需要监听两个主要路由：</p><ul><li><code>/auth</code>：重定向用户至 GitHub 登录授权页面。</li><li><code>/callback</code>：接收 GitHub 返回的 code，换取访问令牌并安全返回给 CMS 前端。</li></ul><h2 id="_3-环境变量设置" tabindex="-1">3. 环境变量设置 <a class="header-anchor" href="#_3-环境变量设置" aria-label="Permalink to &quot;3. 环境变量设置&quot;">​</a></h2><p>在 Cloudflare 后台配置：</p><ul><li><code>GITHUB_CLIENT_ID</code>: OAuth App ID。</li><li><code>GITHUB_CLIENT_SECRET</code>: OAuth App 密钥。</li></ul><h2 id="_4-总结" tabindex="-1">4. 总结 <a class="header-anchor" href="#_4-总结" aria-label="Permalink to &quot;4. 总结&quot;">​</a></h2><p>作为架构中唯一的动态逻辑层，它以 Serverless 形式实现了完整的身份验证闭环。</p>',16)])])}const p=r(t,[["render",u]]);export{_ as __pageData,p as default};
